class _UniffiFfiConverterTypeProllyEngine:
    @staticmethod
    def lift(value: int) -> ProllyEngine:
        return ProllyEngine._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: ProllyEngine):
        if not isinstance(value, ProllyEngine):
            raise TypeError("Expected ProllyEngine instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: ProllyEngine) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> ProllyEngine:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: ProllyEngine, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

class _UniffiFfiConverterInt64(_UniffiConverterPrimitiveInt):
    CLASS_NAME = "i64"
    VALUE_MIN = -2**63
    VALUE_MAX = 2**63

    @staticmethod
    def read(buf):
        return buf.read_i64()

    @staticmethod
    def write(value, buf):
        buf.write_i64(value)

class _UniffiFfiConverterOptionalTypeMutationRecord(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiFfiConverterTypeMutationRecord.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiFfiConverterTypeMutationRecord.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiFfiConverterTypeMutationRecord.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")

